import java.util.Scanner;

public class SignalAmplifier {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int testCases = scanner.nextInt();

        for (int testCase = 1; testCase <= testCases; testCase++) {
            int N = scanner.nextInt(); // Rows
            int M = scanner.nextInt(); // Columns
            int K = scanner.nextInt(); // Number of times laser can be used

            int[][] amp = new int[N][M];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    amp[i][j] = scanner.nextInt();
                }
            }

            System.out.println("#" + testCase + " " + maximizeAmplification(amp, K));
        }

        scanner.close();
    }

    private static int maximizeAmplification(int[][] amp, int K) {
        int N = amp.length;
        int M = amp[0].length;
        int maxFactor = 0;

        // Initial amplification factor
        for (int i = 0; i < N; i++) {
            boolean allPositive = true;
            for (int j = 0; j < M; j++) {
                if (amp[i][j] == 0) {
                    allPositive = false;
                    break;
                }
            }
            if (allPositive) maxFactor++;
        }

        for (int k = 0; k < K; k++) {
            int maxColumnToggleCount = 0;
            int columnToToggle = -1;
            // Find out the column whose toggle will maximize the amplification factor
            for (int j = 0; j < M; j++) {
                int toggleCount = 0;
                for (int i = 0; i < N; i++) {
                    // Count the number of positive rows that can be obtained by toggling this column
                    if ((amp[i][j] == 0 && allOtherColumnsPositive(amp, i, j)) ||
                        (amp[i][j] == 1 && isRowAllPositiveExcept(amp, i, j))) {
                        toggleCount++;
                    }
                }

                if (toggleCount > maxColumnToggleCount) {
                    maxColumnToggleCount = toggleCount;
                    columnToToggle = j;
                }
            }

            if (columnToToggle == -1) break; // No beneficial toggles available, hence break out.

            // Apply the toggle to the chosen column
            for (int i = 0; i < N; i++) {
                amp[i][columnToToggle] = 1 - amp[i][columnToToggle];
            }
            // Update the maximum amplification factor
            maxFactor = Math.max(maxFactor, currentPositiveRowCount(amp));
        }

        return maxFactor;
    }

    // Check if all other columns are positive for the given row
    private static boolean allOtherColumnsPositive(int[][] amp, int row, int colToSkip) {
        for (int j = 0; j < amp[row].length; j++) {
            if (j != colToSkip && amp[row][j] == 0) {
                return false;
            }
        }
        return true;
    }

    // Check if the given row is all positive except for the specified column
    private static boolean isRowAllPositiveExcept(int[][] amp, int row, int colToSkip) {
        for (int j = 0; j < amp[row].length; j++) {
            if (j != colToSkip && amp[row][j] == 0) {
                return false;
            }
        }
        return true;
    }

    // Calculate the current number of all-positive rows
    private static int currentPositiveRowCount(int[][] amp) {
        int count = 0;
        for (int[] row : amp) {
            boolean allPositive = true;
            for (int status : row) {
                if (status == 0) {
                    allPositive = false;
                    break;
                }
            }
            if (allPositive) count++;
        }
        return count;
    }
}
```

